diff --git a/compiler_gym/envs/llvm/llvm_benchmark.py b/compiler_gym/envs/llvm/llvm_benchmark.py
index 193a961e..296838ed 100644
--- a/compiler_gym/envs/llvm/llvm_benchmark.py
+++ b/compiler_gym/envs/llvm/llvm_benchmark.py
@@ -568,8 +568,27 @@ def split_benchmark_by_function(
     if number_of_functions <= 0:
         raise ValueError("No functions found!")

-    # Iterate over the number of functions, extracting each one in turn.
     split_benchmarks: List[Benchmark] = []
+
+    # Extract all of the global initializers into a standalone benchmark.
+    with Popen(
+        [str(llvm.llvm_extract_one_path()), "-", "-const-inits", "-o", "-"],
+        stdout=subprocess.PIPE,
+        stderr=subprocess.PIPE,
+        stdin=subprocess.PIPE,
+    ) as p:
+        stdout, stderr = p.communicate(original_bitcode, timeout=timeout)
+        if p.returncode:
+            raise ValueError(
+                "Failed to extract constant initializers: " f"{stderr.decode('utf-8')}"
+            )
+        original_uri.params["function"] = "<constant initializers>"
+        split_benchmarks.append(
+            Benchmark.from_file_contents(uri=original_uri, data=stdout)
+        )
+        logger.debug("Extracted %s", original_uri)
+
+    # Iterate over the number of functions, extracting each one in turn.
     n = min(number_of_functions, maximum_function_count or number_of_functions)
     for i in range(n):
         with Popen(
diff --git a/compiler_gym/envs/llvm/service/LlvmExtractOne.cc b/compiler_gym/envs/llvm/service/LlvmExtractOne.cc
index 7d108b6a..5b3961d2 100644
--- a/compiler_gym/envs/llvm/service/LlvmExtractOne.cc
+++ b/compiler_gym/envs/llvm/service/LlvmExtractOne.cc
@@ -40,6 +40,9 @@ static cl::opt<int> Nth("n", cl::desc("Extract the n-th function"), cl::value_de
                         cl::init(-1), cl::cat(ExtractOneOptions));
 static cl::opt<bool> CountOnly("count-only", cl::desc("Only count the number of funtions"),
                                cl::init(false), cl::cat(ExtractOneOptions));
+static cl::opt<bool> ConstInits("const-inits",
+                                cl::desc("Keep constant initializers (and export no functions)"),
+                                cl::init(false), cl::cat(ExtractOneOptions));
 static cl::opt<bool> Force("f", cl::desc("Enable binary output on terminals"),
                            cl::cat(ExtractOneOptions));
 static cl::opt<bool> OutputAssembly("S", cl::desc("Write output as LLVM assembly"), cl::Hidden,
@@ -98,19 +101,41 @@ int main(int argc, char** argv) {
     return 0;
   }

-  if (Functions.empty()) {
-    errs() << "No suitable functions\n";
-    return 1;
-  }
-  // Choose one
-  int keeperIndex = (Nth == -1 ? std::rand() : Nth) % Functions.size();
-  Function* Keeper = Functions[keeperIndex];
+  // List of GlobalValues to keep
+  std::vector<GlobalValue*> GVs = {};
+  // Comment to put at the top of the assembly file
+  std::string comment = "";
+
+  if (ConstInits) {
+    // Keep all the constants
+    for (GlobalVariable& GV : Module->globals()) {
+      if (GV.hasInitializer()) {
+        GVs.push_back(&GV);
+      }
+    }
+    // Set the comment
+    comment = "Keep Const Inits";
+  } else {
+    // Work out which function to extract
+    if (Functions.empty()) {
+      errs() << "No suitable functions\n";
+      return 1;
+    }
+    // Choose one
+    int keeperIndex = (Nth == -1 ? std::rand() : Nth) % Functions.size();
+    Function* Keeper = Functions[keeperIndex];

-  // Extract the function
-  ExitOnError ExitOnErr(std::string(*argv) + ": extracting function : ");
-  ExitOnErr(Keeper->materialize());
+    // Extract the function
+    ExitOnError ExitOnErr(std::string(*argv) + ": extracting function : ");
+    ExitOnErr(Keeper->materialize());
+
+    // Put it on the list
+    GVs.push_back(Keeper);
+
+    // Set the comment
+    comment = "KeeperIndex = " + std::to_string(keeperIndex);
+  }
   legacy::PassManager Passes;
-  std::vector<GlobalValue*> GVs = {Keeper};
   Passes.add(createGVExtractionPass(GVs));      // Extract the one function
   Passes.add(createGlobalDCEPass());            // Delete unreachable globals
   Passes.add(createStripDeadDebugInfoPass());   // Remove dead debug info
@@ -128,7 +153,7 @@ int main(int argc, char** argv) {
   }

   if (OutputAssembly) {
-    Out.os() << "; KeeperIndex = " << keeperIndex << '\n';
+    Out.os() << "; " << comment << '\n';
     Passes.add(createPrintModulePass(Out.os(), "", PreserveAssemblyUseListOrder));
   } else if (Force || !CheckBitcodeOutputToConsole(Out.os())) {
     Passes.add(createBitcodeWriterPass(Out.os(), PreserveBitcodeUseListOrder));

