diff --git a/www/frontends/compiler_gym/src/hooks/useThemeDetector.js b/www/frontends/compiler_gym/src/hooks/useThemeDetector.js
new file mode 100644
index 00000000..a5611458
--- /dev/null
+++ b/www/frontends/compiler_gym/src/hooks/useThemeDetector.js
@@ -0,0 +1,30 @@
+/*
+ * Copyright (c) Facebook, Inc. and its affiliates.
+ * This source code is licensed under the MIT license found in the
+ * LICENSE file in the root directory of this source tree.
+ */
+
+import React from "react";
+
+/**
+ * Custom hook to detect user's system theme.
+ * @returns
+ */
+const useThemeDetector = () => {
+  const getCurrentTheme = () =>
+    window.matchMedia("(prefers-color-scheme: dark)").matches;
+  const [isDarkTheme, setIsDarkTheme] = React.useState(getCurrentTheme());
+  const mqListener = (e) => {
+    setIsDarkTheme(e.matches);
+  };
+
+  React.useEffect(() => {
+    const darkThemeMq = window.matchMedia("(prefers-color-scheme: dark)");
+    darkThemeMq.addEventListener('change', mqListener);
+    return () => darkThemeMq.removeEventListener('change',mqListener);
+  }, []);
+
+  return isDarkTheme;
+};
+
+export default useThemeDetector;

