+      benchmark.module().print(rso, /*AAW=*/nullptr);
+      rso.flush();
+
+      const auto lexed        = LexedIR::LexIR(ir);
+      const auto token_ids    = lexed.first.first;
+      const auto token_kind   = lexed.first.second;
+      const auto token_cat    = lexed.second.first;
